function PartySubmissionTimeUnits() {}
PartySubmissionTimeUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/partySubmissionTimeUnits";
PartySubmissionTimeUnits.tabIndex = __tabIdx++;
PartySubmissionTimeUnits.helpText = "Select unit time";
PartySubmissionTimeUnits.mandatoryOn = [PartySubmissionTime.dataBinding];
PartySubmissionTimeUnits.isMandatory = function()
{	var val = Services.getValue(PartySubmissionTime.dataBinding);
	return( null != val && "" != val );
}	
PartySubmissionTimeUnits.isTemporary = function(){  return true; }	
PartySubmissionTimeUnits.enableOn = [PartySubmissionTime.dataBinding];
PartySubmissionTimeUnits.isEnabled = function(){ return PartySubmissionTime.isEnabled();}
PartySubmissionTimeUnits.logicOn = [PartySubmissionTime.dataBinding];
PartySubmissionTimeUnits.logic = function()
{	if(!PartySubmissionTime.isEnabled())
	Services.setValue(PartySubmissionTimeUnits.dataBinding,"");			
}
